Description: 
// Transmitting component
If (ring_frequency != last_ring_frequency) {// From last slow loop.
If (ring_frequency >= PERF_PLIMIT_THRESHOLD) {
Send_p2p_mailbox(ring_frequency) // to all other sockets.
} else {
Send_p2p_mailbox(0)
}
}
// Receiving component
// Receive perf p-limit input from all other sockets over p2p
mailbox.
Perf_p_limit = max(received frequency from all other sockets)
Perf_p_limit -= PERF_PLIMIT_DIFFERENTIAL
Perf_p_limit = max (Perf_p_limit, PERF_PLIMIT_CLIP)
Frequency_floor = max(frequency_floor, Perf_p_limit)

// Conversion factor to go from ring ratio to 75% of the maximum
// theoretical ring bandwidth (above 75% BW utilization, ring performance
// starts to degenerate rapidly).  Ratios steps are in increment of 100MHz,
// so to get the conversion factor is computed as follows:
//
//    BW_limit = (0.5 * ratio * 10^8 Hz * 0.001 s) * 0.75
//    factor   = 37500
//
 %UFS_INTERVAL_SCALE_RP                  8
   Da24c  00000000  &UFS_PREVIOUS_TSC_SNAPSHOT              w   0
   Da250  00a7c5ad  &UFS_MSEC_PER_TSC_TICK                  w   ceil(2**(32+%UFS_INTERVAL_SCALE_RP) / %TSC_TICKS_IN_MS)
   Da254  00000100  &UFS_INTERVAL_SCALE_FACTOR              w   1 << %UFS_INTERVAL_SCALE_RP
   Da258  0000927c  &UFS_RING_THEORETICAL_MAX_BW_FACTOR     w   37500

// Capability ID register (0x06) field definitions
%SVID_REG_CAPABILITY_ID_IOUT_SUPPORT_LSB   0h   // 0 means Iout is not supported. 1 means Iout is supported.
%SVID_REG_CAPABILITY_ID_IOUT_SCALING_LSB   7h   // 0 means LSB=1A. 1 means 0xFF = icc-max

